import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { commitCommand } from "./commands/commit.ts";
import { branchCommand } from "./commands/branch.ts";
import { configCommand } from "./commands/config.ts";
import { initCommand } from "./commands/init.ts";
import denoJson from "../deno.json" with { type: "json" };

const main = new Command()
    .name("shiplog")
    .version(denoJson.version)
    .description("AI-powered git operations")
    .action(function () {
        this.showHelp();
    })
    .command("commit", commitCommand)
    .command("branch", branchCommand)
    .command("config", configCommand)
    .command("init", initCommand);

try {
    await main.parse(Deno.args);
} catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(colors.red(`Error: ${message}`));
    Deno.exit(1);
}

import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { loadConfig } from "../config/loader.ts";
import type { MergedConfig } from "../config/schema.ts";
import { getCommitHistory, getCurrentBranch, getStagedDiff, isGitRepo } from "../git/diff.ts";
import { commit, forcePush, push } from "../git/operations.ts";
import { generate } from "../ai/client.ts";
import { buildCommitPrompt } from "../ai/commit-prompt.ts";
import { sanitizeCommitMessage } from "../ai/sanitize.ts";
import { confirmForcePush, editMessage, selectCommitAction, selectModel } from "../ui/prompts.ts";
import { askUserToOpenLazygit } from "../ui/lazygit.ts";
import { runGuidedCommit } from "../ui/commit-builder.ts";

function extractIssueId(branch: string, pattern?: string, prefix?: string): string | undefined {
    if (!pattern) return undefined;
    const match = branch.match(new RegExp(pattern, "i"));
    if (!match) return undefined;

    if (prefix && match[1]) {
        return `${prefix}${match[1]}`;
    }
    return match[0].toUpperCase();
}

async function ensureStagedChanges(useLazygit: boolean): Promise<void> {
    const diff = await getStagedDiff();
    if (diff) return;

    console.error(colors.yellow("No staged changes found."));

    if (useLazygit) {
        const opened = await askUserToOpenLazygit();
        if (opened) {
            const diffAfterStaging = await getStagedDiff();
            if (!diffAfterStaging) {
                console.log("No changes staged. Aborting.");
                Deno.exit(1);
            }
            return;
        }
    }

    console.error("Please stage your changes first.");
    Deno.exit(1);
}

async function generateCommitMessage(
    model: MergedConfig["model"],
    config: MergedConfig,
    quiet = false,
): Promise<string> {
    const [diff, branch, history] = await Promise.all([
        getStagedDiff(),
        getCurrentBranch(),
        getCommitHistory(config.historyCount),
    ]);

    const issueId = extractIssueId(branch, config.issuePattern, config.issuePrefix);

    const prompt = buildCommitPrompt({
        diff,
        commitHistory: history,
        summaryLength: config.summaryLength,
        issueId,
    });

    if (!quiet) {
        console.error(`Generating with ${colors.cyan(model)}...`);
    }
    const message = await generate(prompt, model, config.provider);
    return sanitizeCommitMessage(message);
}

function displayMessage(message: string, model: string): void {
    console.log("");
    console.log(`Generated commit message (${colors.cyan(model)}):`);
    console.log(colors.dim("─".repeat(40)));
    console.log(colors.yellow(message));
    console.log(colors.dim("─".repeat(40)));
    console.log("");
}

async function handlePush(pushFlag: boolean, forceFlag: boolean): Promise<void> {
    if (!pushFlag) return;

    console.log("");
    console.log("Pushing to remote...");

    if (forceFlag) {
        await forcePush();
        console.log(colors.green("\nAll done! Changes committed and force pushed successfully!\n"));
        return;
    }

    const result = await push();
    if (result.success) {
        console.log(colors.green("\nAll done! Changes committed and pushed successfully!\n"));
        return;
    }

    console.log("");
    console.error(colors.red("Push failed:"));
    console.error(result.output);
    console.log("");

    if (await confirmForcePush()) {
        await forcePush();
        console.log(colors.green("\nAll done! Changes committed and force pushed successfully!\n"));
    } else {
        console.log("Push cancelled.");
        Deno.exit(1);
    }
}

export const commitCommand = new Command()
    .description("Commit changes (manual or AI-powered)")
    .option("-s, --smart", "Use AI to generate commit message")
    .option("-y, --yes", "Auto-confirm (with -s only)")
    .option("-r, --raw", "Print raw message to stdout, no commit (requires -sy)")
    .option("-p, --push", "Push after commit")
    .option("-f, --force", "Force push with --force-with-lease")
    .action(async (options) => {
        if (!await isGitRepo()) {
            console.error(colors.red("Error: Not in a git repository"));
            Deno.exit(1);
        }

        const config = await loadConfig();

        if (options.raw) {
            if (!options.smart || !options.yes) {
                console.error(
                    colors.red("Error: --raw must be used with --smart and --yes (-syr)"),
                );
                Deno.exit(1);
            }
            await ensureStagedChanges(config.useLazygit);
            const message = await generateCommitMessage(config.model, config, true);
            console.log(message);
            return;
        }

        if (!options.smart) {
            await ensureStagedChanges(config.useLazygit);
            await runGuidedCommit(config);
            await handlePush(!!options.push, !!options.force);
            return;
        }

        let currentModel = config.model;
        await ensureStagedChanges(config.useLazygit);
        let commitMessage: string;
        try {
            commitMessage = await generateCommitMessage(currentModel, config);
        } catch (error) {
            console.error(colors.red(`Failed to generate commit message: ${error}`));
            Deno.exit(1);
        }
        displayMessage(commitMessage, currentModel);

        if (options.yes) {
            console.log("Auto-committing (--yes flag)...");
            await commit(commitMessage);
            console.log(colors.green("\nChanges committed successfully!"));
            await handlePush(!!options.push, !!options.force);
            return;
        }

        // Interactive loop
        while (true) {
            const action = await selectCommitAction();

            switch (action) {
                case "commit":
                    console.log("\nCommitting changes...");
                    await commit(commitMessage);
                    console.log(colors.green("\nChanges committed successfully!"));
                    await handlePush(!!options.push, !!options.force);
                    return;

                case "edit": {
                    const edited = await editMessage(commitMessage);
                    if (edited) {
                        console.log("\nCommitting with edited message...");
                        await commit(edited);
                        console.log(colors.green("\nChanges committed successfully!"));
                        await handlePush(!!options.push, !!options.force);
                    } else {
                        console.log("Commit cancelled (empty message).");
                        Deno.exit(1);
                    }
                    return;
                }

                case "regenerate": {
                    const selected = await selectModel(config.models);
                    currentModel = selected;
                    try {
                        commitMessage = await generateCommitMessage(currentModel, config);
                        displayMessage(commitMessage, currentModel);
                    } catch (error) {
                        console.error(colors.red(`Failed to regenerate: ${error}`));
                        console.log("Using previous message.");
                    }
                    break;
                }

                case "cancel":
                    console.log("Commit cancelled.");
                    Deno.exit(1);
            }
        }
    });

import { Confirm, Input, Select } from "@cliffy/prompt";
import * as colors from "@std/fmt/colors";
import type { MergedConfig } from "../config/schema.ts";
import { openInEditor } from "./prompts.ts";
import { commit } from "../git/operations.ts";

export interface CommitParts {
    type: string;
    scope: string;
    breaking: boolean;
    subject: string;
    body: string;
    footer: string;
}

export function buildCommitMessage(parts: CommitParts): string {
    const { type, scope, breaking, subject, body, footer } = parts;

    const scopePart = scope ? `(${scope})` : "";
    const breakingPart = breaking ? "!" : "";
    let message = `${type}${scopePart}${breakingPart}: ${subject}`;

    if (body) message += `\n\n${body}`;
    if (footer) message += `\n\n${footer}`;

    return message;
}

const CUSTOM_OPTION = "✏ custom...";

async function selectWithCustom(message: string, options: string[]): Promise<string> {
    const selected = await Select.prompt({
        message,
        search: true,
        options: [...options.map((o) => ({ name: o, value: o })), {
            name: CUSTOM_OPTION,
            value: CUSTOM_OPTION,
        }],
    }) as string;

    if (selected === CUSTOM_OPTION) {
        return await Input.prompt({ message: `${message} (custom)` });
    }

    return selected;
}

async function promptWithEditorEscape(message: string, initial = ""): Promise<string> {
    const value = await Input.prompt({
        message: `${message} (enter :e to open in $EDITOR)`,
        default: initial,
    });

    if (value === "\x07" || value.trim() === ":e") {
        const edited = await openInEditor(initial);
        return edited ?? initial;
    }

    return value;
}

export async function runGuidedCommit(config: MergedConfig): Promise<void> {
    try {
        await _runGuidedCommit(config);
    } catch (e) {
        if (e instanceof Error && e.message.includes("Interrupted")) {
            console.log("\nCommit cancelled.");
            Deno.exit(1);
        }
        throw e;
    }
}

async function _runGuidedCommit(config: MergedConfig): Promise<void> {
    // 1. Type
    const type = await selectWithCustom("Select commit type", config.commitTypes);

    // 2. Scope
    const scopeRaw = await selectWithCustom("Select scope (Enter to skip)", [
        "(none)",
        ...config.scopes,
    ]);
    const scope = scopeRaw === "(none)" ? "" : scopeRaw;

    // 3. Breaking change
    const breaking = await Confirm.prompt({
        message: "Breaking change?",
        default: false,
    });

    // 4. Subject
    let subject = "";
    while (!subject.trim()) {
        subject = await promptWithEditorEscape("Short description");
        if (!subject.trim()) {
            console.error(colors.red("Subject cannot be empty."));
        }
    }

    // 5. Body
    const body = await promptWithEditorEscape("Body (optional, Enter to skip)");

    // 6. Footer
    const footer = await promptWithEditorEscape(
        "Footer (optional — BREAKING CHANGE: ..., Closes #N)",
    );

    // 7. Preview
    const message = buildCommitMessage({
        type,
        scope: scope.trim(),
        breaking,
        subject: subject.trim(),
        body: body.trim(),
        footer: footer.trim(),
    });

    console.log("");
    console.log("Commit message:");
    console.log(colors.dim("─".repeat(40)));
    console.log(colors.yellow(message));
    console.log(colors.dim("─".repeat(40)));
    console.log("");

    // 8. Confirm
    const confirmed = await Confirm.prompt({ message: "Commit?", default: true });
    if (!confirmed) {
        console.log("Commit cancelled.");
        Deno.exit(1);
    }

    await commit(message);
    console.log(colors.green("\nChanges committed successfully!"));
}

interface CommitPromptOptions {
    diff: string;
    commitHistory: string;
    summaryLength: number;
    issueId?: string;
}

export function buildCommitPrompt(options: CommitPromptOptions): string {
    const { diff, commitHistory, summaryLength, issueId } = options;

    let prompt = `Generate a conventional commit message for the git diff below.

CRITICAL: Return ONLY the commit message. Do not include ANY explanations, analysis, commentary, or additional text. Do not describe what you see in the diff. Just output the commit message and nothing else.

Requirements:
- Summary line MUST NOT exceed ${summaryLength} characters
- Use conventional commit format (type(scope): description)
- Only add body if absolutely necessary for complex changes
- NO explanations, NO analysis, NO commentary

Output format: Just the commit message, nothing more.`;

    if (commitHistory) {
        prompt += `

Previous commits in this feature branch (most recent first):
\`\`\`
${commitHistory}
\`\`\`
Ensure consistency with these commits. Adhere to the ${summaryLength}-character summary rule.`;
    }

    prompt += `

Changes to commit:
\`\`\`
${diff}
\`\`\``;

    if (issueId) {
        prompt += `

Please prefix the summary line with the following issue ID: ${issueId}

Example: ${issueId} feat: some new feature`;
    }

    return prompt;
}

import { ANTHROPIC_MODELS, type AnthropicChatModel, anthropicText } from "@tanstack/ai-anthropic";
import { openRouterText } from "@tanstack/ai-openrouter";

export { ANTHROPIC_MODELS };

type OpenRouterModel = Parameters<typeof openRouterText>[0];

export const PROVIDER_NAMES = ["anthropic", "openrouter"] as const;

export type ProviderName = (typeof PROVIDER_NAMES)[number];

export type ModelName = AnthropicChatModel | OpenRouterModel | string;

export const OPENROUTER_DEFAULT_MODELS = [
    "google/gemma-3-27b-it",
    "google/gemma-3-12b-it",
    "nvidia/nemotron-nano-9b-v2",
] as const;

export function createAdapter(provider: ProviderName, model: ModelName) {
    switch (provider) {
        case "anthropic":
            return anthropicText(model as AnthropicChatModel);
        case "openrouter":
            return openRouterText(model as OpenRouterModel);
        default: {
            const _exhaustive: never = provider;
            throw new Error(`Unknown provider: ${_exhaustive}`);
        }
    }
}

