import { Confirm, Select } from "@cliffy/prompt";

export async function selectCommitAction(): Promise<"commit" | "regenerate" | "edit" | "cancel"> {
    return await Select.prompt({
        message: "What would you like to do?",
        options: [
            { name: "Commit", value: "commit" },
            { name: "Regenerate", value: "regenerate" },
            { name: "Edit", value: "edit" },
            { name: "Cancel", value: "cancel" },
        ],
    }) as "commit" | "regenerate" | "edit" | "cancel";
}

export async function selectBranchAction(): Promise<"create" | "regenerate" | "cancel"> {
    return await Select.prompt({
        message: "What would you like to do?",
        options: [
            { name: "Create Branch", value: "create" },
            { name: "Regenerate", value: "regenerate" },
            { name: "Cancel", value: "cancel" },
        ],
    }) as "create" | "regenerate" | "cancel";
}

export async function selectModel<T extends string>(models: T[]): Promise<T> {
    return await Select.prompt({
        message: "Select model for regeneration:",
        options: models.map((m) => ({ name: m, value: m })),
    }) as T;
}

export async function confirmForcePush(): Promise<boolean> {
    return await Confirm.prompt("Force push with --force-with-lease?");
}

export async function openInEditor(content: string): Promise<string | null> {
    const tmpFile = await Deno.makeTempFile({ suffix: ".txt" });
    await Deno.writeTextFile(tmpFile, content);

    const editor = Deno.env.get("EDITOR") ?? "nvim";
    const command = new Deno.Command(editor, {
        args: [tmpFile],
        stdin: "inherit",
        stdout: "inherit",
        stderr: "inherit",
    });

    const process = command.spawn();
    const status = await process.status;

    if (!status.success) {
        await Deno.remove(tmpFile).catch(() => {});
        return null;
    }

    try {
        const result = (await Deno.readTextFile(tmpFile)).trim();
        return result || null;
    } finally {
        await Deno.remove(tmpFile).catch(() => {});
    }
}

export function editMessage(message: string): Promise<string | null> {
    return openInEditor(message);
}

import * as colors from "@std/fmt/colors";
import { Confirm } from "@cliffy/prompt";

export async function isLazygitInstalled(): Promise<boolean> {
    try {
        const cmd = new Deno.Command("which", {
            args: ["lazygit"],
            stdout: "null",
            stderr: "null",
        });
        const { success } = await cmd.output();
        return success;
    } catch {
        return false;
    }
}

export async function openLazygit(): Promise<void> {
    const command = new Deno.Command("lazygit", {
        stdin: "inherit",
        stdout: "inherit",
        stderr: "inherit",
    });
    const process = command.spawn();
    const status = await process.status;
    if (!status.success) {
        throw new Error("lazygit exited with an error");
    }
}

export async function askUserToOpenLazygit(): Promise<boolean> {
    if (!await isLazygitInstalled()) {
        console.error(colors.red("lazygit is not installed."));
        console.error("Install with: brew install lazygit");
        return false;
    }

    const confirmed = await Confirm.prompt("Open lazygit to stage changes?");
    if (!confirmed) return false;

    await openLazygit();
    return true;
}

import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { loadConfig } from "../config/loader.ts";
import type { MergedConfig } from "../config/schema.ts";
import { switchToNewBranch } from "../git/operations.ts";
import { isGitRepo } from "../git/diff.ts";
import { generate } from "../ai/client.ts";
import { buildBranchPrompt } from "../ai/branch-prompt.ts";
import { sanitizeBranchName } from "../ai/sanitize.ts";
import { selectBranchAction, selectModel } from "../ui/prompts.ts";

async function generateBranchName(
    description: string,
    model: MergedConfig["model"],
    config: MergedConfig,
    quiet = false,
): Promise<string> {
    const prompt = buildBranchPrompt({ description });

    if (!quiet) {
        console.error(`Generating with ${colors.cyan(model)}...`);
    }
    const name = await generate(prompt, model, config.provider);
    return sanitizeBranchName(name);
}

function displayBranchName(name: string, model: string): void {
    console.log("");
    console.log(`Generated branch name (${colors.cyan(model)}):`);
    console.log(colors.dim("─".repeat(40)));
    console.log(colors.yellow(name));
    console.log(colors.dim("─".repeat(40)));
    console.log("");
}

export const branchCommand = new Command()
    .description("Create branches (manual or AI-powered)")
    .arguments("[description...:string]")
    .option("-s, --smart", "Use AI to generate branch name")
    .option("-y, --yes", "Auto-create branch (with -s only)")
    .option("-r, --raw", "Print raw name to stdout, no branch creation (requires -sy)")
    .action(async (options, ...descriptionParts) => {
        if (!await isGitRepo()) {
            console.error(colors.red("Error: Not in a git repository"));
            Deno.exit(1);
        }

        const description = descriptionParts.join(" ");

        if (!description) {
            console.error(colors.red("Error: No branch name or description provided"));
            console.error("Use 'shiplog branch --help' for usage information");
            Deno.exit(1);
        }

        if (options.raw) {
            if (!options.smart || !options.yes) {
                console.error(
                    colors.red("Error: --raw must be used with --smart and --yes (-syr)"),
                );
                Deno.exit(1);
            }
            const config = await loadConfig();
            const name = await generateBranchName(description, config.model, config, true);
            console.log(name);
            return;
        }

        if (!options.smart) {
            console.log(`Creating branch: ${colors.cyan(description)}`);
            await switchToNewBranch(description);
            console.log(
                colors.green(`\nBranch '${description}' created and switched successfully!`),
            );
            return;
        }

        const config = await loadConfig();
        let currentModel = config.model;
        let branchName: string;
        try {
            branchName = await generateBranchName(description, currentModel, config);
        } catch (error) {
            console.error(colors.red(`Failed to generate branch name: ${error}`));
            Deno.exit(1);
        }
        displayBranchName(branchName, currentModel);

        if (options.yes) {
            console.log("Auto-creating branch (--yes flag)...");
            await switchToNewBranch(branchName);
            console.log(
                colors.green(`\nBranch '${branchName}' created and switched successfully!`),
            );
            return;
        }

        // Interactive loop
        while (true) {
            const action = await selectBranchAction();

            switch (action) {
                case "create":
                    console.log("\nCreating branch...");
                    await switchToNewBranch(branchName);
                    console.log(
                        colors.green(`\nBranch '${branchName}' created and switched successfully!`),
                    );
                    return;

                case "regenerate": {
                    const selected = await selectModel(config.models);
                    currentModel = selected;
                    try {
                        branchName = await generateBranchName(description, currentModel, config);
                        displayBranchName(branchName, currentModel);
                    } catch (error) {
                        console.error(colors.red(`Failed to regenerate: ${error}`));
                        console.log("Using previous name.");
                    }
                    break;
                }

                case "cancel":
                    console.log("Branch creation cancelled.");
                    Deno.exit(1);
            }
        }
    });

import { Command } from "@cliffy/command";
import { stringify as stringifyToml } from "@std/toml";
import * as colors from "@std/fmt/colors";
import { loadConfig } from "../config/loader.ts";
import { CONFIG_DIR, GLOBAL_CONFIG_PATH } from "../config/paths.ts";
import { GlobalConfigSchema } from "../config/schema.ts";

/** Convert camelCase keys to snake_case for TOML output */
function camelToSnake(obj: Record<string, unknown>): Record<string, unknown> {
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
        const snakeKey = key.replace(/[A-Z]/g, (c) => `_${c.toLowerCase()}`);
        result[snakeKey] = value;
    }
    return result;
}

async function initGlobalConfig(): Promise<void> {
    try {
        await Deno.stat(GLOBAL_CONFIG_PATH);
        console.error(colors.yellow(`Config already exists at ${GLOBAL_CONFIG_PATH}`));
        console.error("Delete it first if you want to regenerate.");
        Deno.exit(1);
    } catch (e) {
        if (!(e instanceof Deno.errors.NotFound)) throw e;
    }

    await Deno.mkdir(CONFIG_DIR, { recursive: true });

    const defaults = GlobalConfigSchema.parse({});
    const tomlContent = stringifyToml(camelToSnake(defaults as Record<string, unknown>));

    await Deno.writeTextFile(GLOBAL_CONFIG_PATH, tomlContent);
    console.log(colors.green(`Config written to ${GLOBAL_CONFIG_PATH}`));
}

async function showConfig(): Promise<void> {
    const config = await loadConfig();
